import{_ as n,C as o,o as s,c as l,E as t,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Malta Legal Rights","description":"Legal rights for transgender people in Malta","frontmatter":{"layout":"doc","title":"Malta Legal Rights","description":"Legal rights for transgender people in Malta"},"headers":[],"relativePath":"europe/malta/legal-rights.md","filePath":"europe/malta/legal-rights.md","lastUpdated":null}'),g={name:"europe/malta/legal-rights.md"};function h(c,e,m,p,u,f){const a=o("Badge");return s(),l("div",null,[t(a,{variant:"yellow"},{default:i(()=>[...e[0]||(e[0]=[r("Self-ID since 2015",-1)])]),_:1}),t(a,{variant:"green"},{default:i(()=>[...e[1]||(e[1]=[r("Constitutional Protections",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-malta" tabindex="-1">Legal Rights in Malta <a class="header-anchor" href="#legal-rights-in-malta" aria-label="Permalink to &quot;Legal Rights in Malta&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Malta adopted a self-determination model for legal gender recognition through the <strong>Gender Identity, Gender Expression and Sex Characteristics Act (GIGESC Act)</strong> in April 2015. This was a landmark law — the first in Europe to enshrine constitutional-level protections for gender identity and gender expression.</p><p>The process requires:</p><ul><li>A simple declaration before a notary</li><li>No medical certificates, surgery, or psychological assessments</li><li>No minimum period of living in the affirmed gender</li><li>Recognition for minors with parental consent (with judicial oversight for under-16s)</li></ul><p>The law also explicitly prohibits any requirement for sterilisation, divorce, or medical treatment as a condition for gender recognition.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes are processed alongside gender recognition through the same notarial deed. Alternatively, name changes can be done separately through the Public Registry. The process is simple and does not require medical documentation.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>The GIGESC Act provides some of the strongest anti-discrimination protections in Europe:</p><ul><li><strong>Employment</strong> — Prohibited discrimination in hiring, promotion, and termination</li><li><strong>Healthcare</strong> — Right to access gender affirming healthcare without discrimination</li><li><strong>Education</strong> — Protection for students and staff</li><li><strong>Housing</strong> — Prohibited discrimination in rental and purchase</li><li><strong>Goods and Services</strong> — Full access regardless of gender identity or expression</li><li><strong>Conversion therapy</strong> — Banned since 2016</li></ul><p>The law also established the <strong>Human Rights and Equality Commission</strong> to enforce these protections.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Malta&#39;s Criminal Code includes gender identity and gender expression as protected characteristics under hate crime legislation. Hate crimes motivated by transphobia carry enhanced penalties. The law covers:</p><ul><li>Violence and assault</li><li>Threats and harassment</li><li>Incitement to hatred</li><li>Property damage</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Human Rights and Equality Commission</strong> — <a href="https://equality.gov.mt/" target="_blank" rel="noreferrer">equality.gov.mt</a></li><li><strong>MGRM (Malta Gay Rights Movement)</strong> — <a href="https://www.maltagayrights.net/" target="_blank" rel="noreferrer">maltagayrights.net</a></li><li><strong>Deputy Prime Minister&#39;s Office</strong> — Gender identity policy: <a href="https://depi.gov.mt/" target="_blank" rel="noreferrer">depi.gov.mt</a></li><li><strong>ILGA-Europe - Malta Country Report</strong> — <a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ilga-europe.org</a></li></ul>',17))])}const w=n(g,[["render",h]]);export{b as __pageData,w as default};
